jQuery.Class("Settings_Users_Locks_Js",{},{registerAdd:function(e){var t=this;e.find(".addItem").click(function(s){var n=parseInt(e.find("#lcount").val())+1,i=($(s.currentTarget),e.find(".cloneItem tbody").clone(!0,!0));i.find("tr").attr("data-id",n).addClass("row"+n),e.find(".locksTable tbody").append(i.html()),e.find("#lcount").val(n),t.registerDelete(e.find("tr.row"+n)),app.showSelect2ElementView(e.find("tr.row"+n).find("select"))})},registerDelete:function(e){e.find(".delate").click(function(e){$(e.currentTarget).closest("tr").remove()})},registerSave:function(e){e.find(".saveItems").click(function(t){var s=[];e.find(".locksTable tbody tr").each(function(e){s.push({user:$(this).find(".users").val(),locks:$(this).find(".locks").val()})}),app.saveAjax("saveLocks",s).then(function(e){Settings_Vtiger_Index_Js.showMessage({type:"success",text:e.result.message})})})},registerEvents:function(){var e=$(".contentsDiv");this.registerAdd(e),this.registerDelete(e),this.registerSave(e)}});